SELECT COUNT(DISTINCT T1.passenger_id) AS passenger_count
FROM trips AS T1
JOIN evaluations AS T3 ON T1.route_id = T3.route_id;

SELECT COUNT(DISTINCT passenger_id) AS unique_passenger_count
FROM feedback
WHERE route_id = 1;

SELECT AVG(score) AS avg_adaptability_rating
FROM evaluation_scores
WHERE category_id = (SELECT category_id FROM evaluation_categories WHERE category_name = 'Adaptability');

SELECT COUNT(DISTINCT t.passenger_id) AS total_passengers
FROM trips t
WHERE t.duration_minutes > 120;

SELECT mode_name
FROM transportation_modes
WHERE capacity = (SELECT MAX(capacity) FROM transportation_modes);

SELECT route_id
FROM evaluation_scores
WHERE score_id = 0;
